1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
11	export type Step = QuoteStep | ClaimStep;
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type QuoteResult = { premium: number };
19	export type ClaimResult = { payout: number; remainingCap: number };
20	export type StepResult = QuoteResult | ClaimResult;
21	export type ScenarioResult = { results: StepResult[] };
22	
23	const PROCESSING_FEE = 5;
24	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const INSURANCE_VALUES: Record<string, number> = {
36	  sword: 1000,
37	  amulet: 600,
38	  staff: 800,
39	  potion: 400,
40	  rune: 250,
41	  moonstone: 250,
42	};
43	
44	const DEDUCTIBLE = 100;
45	const CAP_MULTIPLIER = 2;
46	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
47	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
48	const DRAGON_MATERIAL = "dragon";
49	
50	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
51	const BLOCK_SIZE = 3;
52	const BLOCK_BASE_PREMIUM = 60;
53	
54	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
55	
56	const countByType = (items: Item[]): Record<string, number> => {
57	  const counts: Record<string, number> = {};
58	  for (const item of items) {
59	    counts[item.type] = (counts[item.type] ?? 0) + 1;
60	  }
61	  return counts;
62	};
63	
64	const componentGroupPremium = (type: string, count: number): number =>
65	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
66	
67	const itemsBasePremium = (items: Item[]): number => {
68	  const mainItems = items.filter((item) => !isComponent(item));
69	  const components = items.filter(isComponent);
70	  const mainTotal = mainItems.reduce(
71	    (sum, item) => sum + BASE_PREMIUMS[item.type],
72	    0,
73	  );
74	  const componentTotal = Object.entries(countByType(components)).reduce(
75	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
76	    0,
77	  );
78	  return mainTotal + componentTotal;
79	};
80	
81	const CURSE_SURCHARGE_RATE = 0.5;
82	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
83	const HIGH_ENCHANTMENT_THRESHOLD = 5;
84	
85	const itemModifiersSurcharge = (item: Item): number => {
86	  const base = BASE_PREMIUMS[item.type];
87	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
88	  const highEnchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
89	  return curse + highEnchantment;
90	};
91	
92	const sumItemModifiers = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + itemModifiersSurcharge(item), 0);
94	
95	const LOYALTY_DISCOUNT_RATE = 0.2;
96	const LOYALTY_YEARS_THRESHOLD = 2;
97	
98	const policyLevelAdjustments = (basePremium: number, yearsWithMHPCO: number): number => {
99	  const firstContract = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
100	  const loyalty = yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -basePremium * LOYALTY_DISCOUNT_RATE : 0;
101	  return firstContract + loyalty;
102	};
103	
104	const quoteStep = (step: QuoteStep, yearsWithMHPCO: number): QuoteResult => {
105	  const basePremium = itemsBasePremium(step.items);
106	  const itemModifiers = sumItemModifiers(step.items);
107	  const policyAdjustments = policyLevelAdjustments(basePremium, yearsWithMHPCO);
108	  const premium = basePremium + itemModifiers + policyAdjustments + PROCESSING_FEE;
109	  return { premium: Math.ceil(premium) };
110	};
111	
112	type PolicyState = { items: Item[]; insuranceSum: number; remainingCap: number };
113	
114	const insuranceSum = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
116	
117	const reimbursableAmount = (item: Item | undefined, amount: number): number => {
118	  if ((item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) return amount * HIGH_ENCHANTMENT_CLAIM_RATE;
119	  if (item?.material === DRAGON_MATERIAL) return amount;
120	  return amount;
121	};
122	
123	const damagePayout = (damage: Damage, items: Item[]): number => {
124	  const item = items.find((i) => i.type === damage.itemType);
125	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
126	};
127	
128	const claimStep = (step: ClaimStep, policies: Map<number, PolicyState>): ClaimResult => {
129	  const policy = policies.get(step.policy)!;
130	  const totalPayout = step.incident.damages.reduce(
131	    (sum, dmg) => sum + damagePayout(dmg, policy.items),
132	    0,
133	  );
134	  policy.remainingCap -= totalPayout;
135	  return { payout: totalPayout, remainingCap: policy.remainingCap };
136	};
137	
138	const newPolicyState = (items: Item[]): PolicyState => {
139	  const sum = insuranceSum(items);
140	  return { items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER };
141	};
142	
143	export const runScenario = (scenario: Scenario): ScenarioResult => {
144	  const policies = new Map<number, PolicyState>();
145	  const results: StepResult[] = [];
146	  scenario.steps.forEach((step, idx) => {
147	    if (step.op === "quote") {
148	      results.push(quoteStep(step, scenario.customer.yearsWithMHPCO));
149	      policies.set(idx, newPolicyState(step.items));
150	    } else {
151	      results.push(claimStep(step, policies));
152	    }
153	  });
154	  return { results };
155	};
